+import { NormalizedErrorStackOptions } from './error-options.js';
+
+export function normalizeStackNewlines(stack: string): string {
+  return stack.replace(/\\r\
?/g, '\
');
+}
+
+function stripInternal(line: string, option: NormalizedErrorStackOptions): boolean {
+  const node = option.stripInternalFrames === 'node' || option.stripInternalFrames === 'node_and_superjson';
+  const superjson = option.stripInternalFrames === 'superjson' || option.stripInternalFrames === 'node_and_superjson';
+  return (node && line.includes('node:internal')) ||
+    (superjson && ['src/transformer.ts', 'src/plainer.ts', 'src/index.ts'].some(path => line.includes(path)));
+}
+
+function redactPath(line: string, option: NormalizedErrorStackOptions): string {
+  if (option.redactPaths === 'none') return line;
+  if (option.redactPaths === 'strip_cwd') {
+    const cwd = process.cwd().replace(/\\\\/g, '/');
+    return line.replaceAll(cwd, '');
+  }
+  return line.replace(/(?:[A-Za-z]:)?(?:\\/[^\\s():]+)+/g, path => path.slice(path.lastIndexOf('/') + 1));
+}
+
+function initialLines(stack: string, option: NormalizedErrorStackOptions): string[] {
+  const normalized = option.normalizeNewlines ? normalizeStackNewlines(stack) : stack;
+  return normalized.split('\
').map((line, index) =>
+    index > 0 && option.trimLeadingWhitespace ? line.replace(/^\\s+/, '') : line
+  );
+}
+
+export function processStackString(stack: string, option: NormalizedErrorStackOptions): string {
+  let lines = initialLines(stack, option).map(line => redactPath(line, option));
+  if (option.maxStackLines !== undefined) lines = lines.slice(0, option.maxStackLines);
+  return [lines[0], ...lines.slice(1).filter(line => !stripInternal(line, option))].join('\
');
+}
+
+export function processStackFrames(
+  stack: string,
+  option: NormalizedErrorStackOptions
+): Array<{ raw: string }> {
+  let lines = initialLines(stack, option);
+  lines = [lines[0], ...lines.slice(1).filter(line => !stripInternal(line, option))];
+  lines = lines.map(line => redactPath(line, option));
+  if (option.maxStackLines !== undefined) lines = lines.slice(0, option.maxStackLines);
+  return lines.map(raw => ({ raw }));
+}
