+
+function errorAnnotation(error: Error, superJson: SuperJSON): SimpleTypeAnnotation {
+  const options = superJson.errorStackOptions;
+  if (!options || !matchesClassFilter(error, options)) return 'Error';
+  if (options.mode === 'string') return 'Error/stack';
+  if (options.mode === 'frames') return 'Error/frames';
+  return 'Error';
+}
+
+function serializeLegacyError(error: Error, superJson: SuperJSON): Record<string, any> {
+  const plain: Record<string, any> = { name: error.name, message: error.message };
+  if ('cause' in error) plain.cause = (error as any).cause;
+  superJson.allowedErrorProps.forEach(prop => {
+    plain[prop] = (error as any)[prop];
+  });
+  return plain;
+}
+
+function serializeConfiguredError(
+  error: Error,
+  superJson: SuperJSON,
+  options: NormalizedErrorStackOptions,
+  depth: number,
+  seen: Set<Error>
+): Record<string, any> {
+  const matches = matchesClassFilter(error, options);
+  const plain: Record<string, any> = {
+    name: error.name,
+    message:
+      matches && options.sanitizeMessage
+        ? sanitizeMessage(error.message)
+        : error.message,
+  };
+
+  // Stack fields are controlled exclusively by errorStack, never by allowErrorProps.
+  if (matches && options.mode === 'string' && superJson.allowedErrorProps.includes('stack') && typeof error.stack === 'string') {
+    plain.stack = processStackString(error.stack, options);
